mapper.select:
SELECT p.id, p.name, p.active, p.currency_id AS currencyId, p.company_id AS companyId FROM product_pricelist p LEFT JOIN res_currency rcur ON rcur.id = p.currency_id LEFT JOIN res_company rco ON rco.id = p.company_id
AND ( p.name ILIKE CONCAT('%', #{query.keyword}, '%') OR rcur.name ILIKE CONCAT('%', #{query.keyword}, '%') OR rcur.symbol ILIKE CONCAT('%', #{query.keyword}, '%') OR rco.name ILIKE CONCAT('%', #{query.keyword}, '%') )
AND p.name ILIKE CONCAT('%', #{query.name}, '%')
AND p.active = #{query.active}
AND p.currency_id = #{query.currencyId}
AND ( rcur.name ILIKE CONCAT('%', #{query.currencyName}, '%') OR rcur.symbol ILIKE CONCAT('%', #{query.currencyName}, '%') )
AND p.company_id = #{query.companyId}
AND rco.name ILIKE CONCAT('%', #{query.companyName}, '%')
ORDER BY p.id DESC
